package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatWithRecordSeparatorTest {

    @Test
    void testWithRecordSeparator_NewInstanceWithDifferentSeparator() {
        CSVFormat original = CSVFormat.DEFAULT;
        String newSeparator = "\n";

        CSVFormat changed = original.withRecordSeparator(newSeparator);

        assertNotSame(original, changed);
        assertEquals(newSeparator, changed.getRecordSeparator());
        // Original remains unchanged
        assertEquals(CSVFormat.DEFAULT.getRecordSeparator(), original.getRecordSeparator());
    }

    @Test
    void testWithRecordSeparator_NullSeparator() {
        CSVFormat original = CSVFormat.DEFAULT;
        String newSeparator = null;

        CSVFormat changed = original.withRecordSeparator(newSeparator);

        assertNotSame(original, changed);
        assertNull(changed.getRecordSeparator());
        assertEquals(CSVFormat.DEFAULT.getRecordSeparator(), original.getRecordSeparator());
    }

    @Test
    void testWithRecordSeparator_EmptyStringSeparator() {
        CSVFormat original = CSVFormat.DEFAULT;
        String newSeparator = "";

        CSVFormat changed = original.withRecordSeparator(newSeparator);

        assertNotSame(original, changed);
        assertEquals("", changed.getRecordSeparator());
        assertEquals(CSVFormat.DEFAULT.getRecordSeparator(), original.getRecordSeparator());
    }

}
